oxy_webhelp_navlinks = {"vmware_cloud_director_vapps-d30753e27795":{"topics":[{"title":"Protection and management features","shortdesc":"<p class=\"shortdesc\">In addition to full SLA-Domain-based protection of vApps, other features available         for vSphere virtual machines are also provided for vApps.<\/p>","href":"vcd\/protection_and_management_features.html","attributes":{"data-id":"protection_and_management_features"},"menu":{"hasChildren":false},"tocID":"protection_and_management_features-d30753e27806","topics":[]},{"title":"Metadata protection","shortdesc":"<p class=\"shortdesc\">Protection of vApps by Rubrik includes the metadata of the vApp.<\/p>","href":"vcd\/metadata_protection.html","attributes":{"data-id":"metadata_protection"},"menu":{"hasChildren":false},"tocID":"metadata_protection-d30753e27817","topics":[]},{"title":"Minimum privileges granted by VMware Cloud Director ","shortdesc":"<p class=\"shortdesc\">To perform the required operations on the objects hosted by a software-defined data         center, Rubrik cluster requires a few minimum privileges. These minimum required privileges         are granted to the Rubrik cluster by the user role assigned to the VMware Cloud Director         account used by the Rubrik cluster.<\/p>","href":"cdm\/vcd\/minimum_vmware_cloud_director_privileges.html","attributes":{"data-id":"minimum_vmware_cloud_director_privileges"},"menu":{"hasChildren":false},"tocID":"minimum_vmware_cloud_director_privileges-d30753e27828","next":"minimum_vmware_cloud_director_privileges-d30753e27828"},{"title":"vApps limitations","shortdesc":"<p class=\"shortdesc\">Information about the specific limitations for vApps support provided by         Rubrik.<\/p>","href":"vcd\/vapps_limitations.html","attributes":{"data-id":"vapps_limitations"},"menu":{"hasChildren":false},"tocID":"vapps_limitations-d30753e27927","topics":[]},{"title":"Protection hierarchy for VMware Cloud Director","shortdesc":"<p class=\"shortdesc\">You can protect virtual machines through several levels of the VMware Cloud Director         management hierarchy.<\/p>","href":"vcd\/vmw_cd_protection_hierarchy.html","attributes":{"data-id":"vmw_cd_protection_hierarchy"},"menu":{"hasChildren":false},"tocID":"vmw_cd_protection_hierarchy-d30753e27938","next":"vmw_cd_protection_hierarchy-d30753e27938"},{"title":"VMware Cloud Director instances","shortdesc":"<p class=\"shortdesc\">A Rubrik cluster works with vApps through VMware Cloud Director instances.<\/p>","href":"vcd\/vmware_cloud_director_instances.html","attributes":{"data-id":"vmware_cloud_director_instances"},"menu":{"hasChildren":false},"tocID":"vmware_cloud_director_instances-d30753e27971","next":"vmware_cloud_director_instances-d30753e27971"},{"title":"vApp management","shortdesc":"<p class=\"shortdesc\">After a VMware Cloud Director instance is added, the Rubrik cluster provides methods     for finding, viewing, and protecting the vApps.<\/p>","href":"vcd\/vapp_management.html","attributes":{"data-id":"vapp_management"},"menu":{"hasChildren":false},"tocID":"vapp_management-d30753e28026","next":"vapp_management-d30753e28026"},{"title":"Recovery and restore of vApp data","shortdesc":"<p class=\"shortdesc\">You can use Instant Recovery, Export, or file-level recovery to recover data from a     vApp snapshot.<\/p>","href":"vcd\/recovery_restore_vapp_data.html","attributes":{"data-id":"recovery_restore_vapp_data"},"menu":{"hasChildren":false},"tocID":"recovery_restore_vapp_data-d30753e28136","next":"recovery_restore_vapp_data-d30753e28136"}]}};